/* Evidence: cmem-optimization-preserves-contract-j409k4 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 4807; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int evidence_cmem_optimization_preserves_contract_j409k4(size_t live, size_t reserved, size_t peak, size_t limit, size_t *waste) {
  if (waste == NULL || live > reserved || reserved > peak || peak > limit) return 0;
  *waste = reserved - live;
  return 1;
}

int main(void) {
  size_t waste = 0;
  int rejected = evidence_cmem_optimization_preserves_contract_j409k4(40, 32, 64, 128, &waste);
  int accepted = evidence_cmem_optimization_preserves_contract_j409k4(2, 10, 18, 128, &waste);
  int invariant = !rejected && accepted && waste == 8u;
  printf("profile waste=%lu invariant=%d\n", (unsigned long)waste, invariant);
  return invariant ? 0 : 1;
}
